#include<bits/stdc++.h>
using namespace std;
int a[3030][3030],s[3030][3030];
int n,m,k;
bool check(int x,int y,int l)
{
    int x_1=x+l-1,y_1=y+l-1;
    if(x_1>n||y_1>m)
    {
        return false;
    }
    return (s[x_1][y_1]-s[x-1][y_1]-s[x_1][y-1]+s[x-1][y-1])==0;
}
int main()
{
    scanf("%d%d%d",&n,&m,&k);
    for(int i=1;i<=k;i++)
    {
        int x,y;
        scanf("%d%d",&x,&y);
        a[x][y]=1;
    }
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=m;j++)
        {
            s[i][j]=s[i-1][j]+s[i][j-1]-s[i-1][j-1]+a[i][j];
        }
    }
    long long ans=0;
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=m;j++)if(a[i][j]==0)
        {
            int l=1,r=min(n,m),best=0;
            while(l<=r)
            {
                int mid=(l+r)/2;
                if(check(i,j,mid))
                {
                    best=mid;
                    l=mid+1;
                }
                else
                {
                    r=mid-1;
                }
            }
            ans+=best;
        }
    }
    printf("%lld",ans);
    return 0;
}
